func NewMultiReporter(reporters ...Reporter) *MultiReporter {
	return &MultiReporter{reporters: reporters}
}

func (m *MultiReporter) PrereqStart(name string) {
	for _, r := range m.reporters {
		r.PrereqStart(name)
	}
}

