	for _, rep := range m.reporters {
		rep.PrereqResult(r)
	}
}

func (m *MultiReporter) TestStart(name string) {
	for _, r := range m.reporters {
		r.TestStart(name)
	}
}

func (m *MultiReporter) TestResult(r TestResultData) {
	for _, rep := range m.reporters {
		rep.TestResult(r)
	}
}

