2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"strings"
8	)
9	
10	type formatEntry struct {
11		filename string
12		factory  func(io.Writer) Reporter
13	}
14	
15	var formats = map[string]formatEntry{
16		"terminal":   {"smoke-output.txt", func(w io.Writer) Reporter { return NewTerminal(w) }},
17		"json":       {"smoke-results.json", func(w io.Writer) Reporter { return NewJSON(w) }},
18		"junit":      {"smoke-junit.xml", func(w io.Writer) Reporter { return NewJUnit(w) }},
19		"tap":        {"smoke-tap.txt", func(w io.Writer) Reporter { return NewTAP(w) }},
20		"prometheus": {"smoke-metrics.prom", func(w io.Writer) Reporter { return NewPrometheus(w) }},
21	}
22	
23	// Chain parses a comma-separated format string, creates reporters for each
24	// format, and wraps them in a MultiReporter. The first format writes to
25	// stdout; subsequent formats write to auto-named files in the working
26	// directory. Returns the reporter, any opened files (creation order, close
27	// in reverse), or an error.
28	func Chain(format string, stdout io.Writer) (Reporter, []io.Closer, error) {
29		names := parseFormats(format)
30		if len(names) == 0 {
31			return nil, nil, fmt.Errorf("no output format specified")
32		}
33	
34		for _, n := range names {
35			if _, ok := formats[n]; !ok {
36				return nil, nil, fmt.Errorf("unknown format %q (valid: terminal, json, junit, tap, prometheus)", n)
37			}
38		}
39	
40		var reporters []Reporter
41		var closers []io.Closer
42	
43		for i, name := range names {
44			entry := formats[name]
45			var w io.Writer
46			if i == 0 {
47				w = stdout
48			} else {
49				f, err := os.Create(entry.filename)
50				if err != nil {
51					for j := len(closers) - 1; j >= 0; j-- {
52						closers[j].Close()
53					}
54					return nil, nil, fmt.Errorf("creating %s: %w", entry.filename, err)
55				}
56				closers = append(closers, f)
57				w = f
58			}
59			reporters = append(reporters, entry.factory(w))
60		}
61	
62		if len(reporters) == 1 {
63			return reporters[0], closers, nil
64		}
65		return NewMultiReporter(reporters...), closers, nil
66	}
67	
68	func parseFormats(format string) []string {
69		parts := strings.Split(format, ",")
70		var names []string
71		seen := make(map[string]bool)
72		for _, p := range parts {
73			name := strings.ToLower(strings.TrimSpace(p))
74			if name == "" || seen[name] {
75				continue
76			}
77			seen[name] = true
78			names = append(names, name)
79		}
80		return names
81	}
82	
