75					Name:   pr.Name,
76					Passed: pr.Passed,
77					Output: pr.Output,
78					Hint:   pr.Hint,
79					Error:  pr.Error,
80				})
81			}
82			// Check for prereq failures
83			for _, pr := range results {
84				if !pr.Passed {
85					return nil, fmt.Errorf("prerequisite %q failed: %v", pr.Name, pr.Error)
86				}
87			}
88		}
89	
90		// Filter tests by tags
91		tests := filterTests(r.Config.Tests, opts.Tags, opts.ExcludeTags)
92	
93		// Initialize trace context if otel is enabled
94		if r.Config.OTel.Enabled {
95			r.trace = NewTraceContext()
96			if r.TraceHealth == nil {
97				r.TraceHealth = NewTraceHealthTracker(10)
98			}
99		}
100	
101		suite := &SuiteResult{
102			Project: r.Config.Project,
103			Total:   len(tests),
104		}
105	
106		failFast := opts.FailFast || r.Config.Settings.FailFast
107	
108		if r.Config.Settings.Parallel && !failFast {
109			r.runParallel(tests, opts, suite)
110		} else {
111			r.runSequential(tests, opts, suite, failFast)
112		}
113	
