117		summaryData := reporter.SuiteResultData{
118			Project:         suite.Project,
119			Total:           suite.Total,
120			Passed:          suite.Passed,
121			Failed:          suite.Failed,
122			Skipped:         suite.Skipped,
123			AllowedFailures: suite.AllowedFailures,
124			Duration:        suite.Duration,
125		}
126		if r.TraceHealth != nil && r.TraceHealth.Total() > 0 {
127			summaryData.TraceHealthPct = r.TraceHealth.HealthPct()
128			summaryData.TraceDegraded = r.TraceHealth.Degraded(50.0)
129		}
130		r.Reporter.Summary(summaryData)
