178	func (r *Runner) runSequential(tests []schema.Test, opts RunOptions, suite *SuiteResult, failFast bool) {
179		stopped := false
180		for _, t := range tests {
181			if stopped {
182				tr := TestResult{Name: t.Name, Skipped: true}
183				suite.Tests = append(suite.Tests, tr)
184				suite.Skipped++
185				r.Reporter.TestStart(t.Name)
186				r.Reporter.TestResult(reporter.TestResultData{Name: t.Name, Skipped: true})
187				continue
188			}
189	
190			tr := r.runTest(t, opts)
191			suite.Tests = append(suite.Tests, tr)
192			if tr.Passed {
193				suite.Passed++
194			} else if tr.Skipped {
195				suite.Skipped++
196			} else if tr.AllowedFailure {
197				suite.AllowedFailures++
198			} else {
199				suite.Failed++
200				if failFast {
201					stopped = true
202				}
203			}
204		}
205	}
