234	func (r *Runner) runTest(t schema.Test, opts RunOptions) TestResult {
235		if t.Retry == nil || t.Retry.Count <= 1 {
236			res := r.runTestOnce(t, opts)
237			if res.Attempts == 0 {
238				res.Attempts = 1
239			}
240			return res
241		}
242		var last TestResult
243		backoff := t.Retry.Backoff.Duration
244		for attempt := 1; attempt <= t.Retry.Count; attempt++ {
245			last = r.runTestOnce(t, opts)
246			if last.Passed {
247				last.Attempts = attempt
248				return last
249			}
250			if t.Retry.RetryOnTraceOnly && traceConfirmed(last.Assertions) {
251				last.Attempts = attempt
252				return last
253			}
254			if attempt < t.Retry.Count {
255				time.Sleep(backoff)
256				backoff *= 2
257			}
258		}
259		last.Attempts = t.Retry.Count
260		return last
261	}
