631				continue
632			}
633			filtered = append(filtered, t)
634		}
635		return filtered
636	}
637	
638	func hasAnyTag(tags, targets []string) bool {
639		for _, tag := range tags {
640			for _, target := range targets {
641				if strings.EqualFold(tag, target) {
642					return true
643				}
644			}
645		}
646		return false
647	}
