649	// shouldSkip evaluates skip_if conditions and returns true if the test should be skipped.
650	func shouldSkip(si *schema.SkipIf, configDir string) bool {
651		if si == nil {
652			return false
653		}
654		if si.EnvUnset != "" {
655			if _, ok := os.LookupEnv(si.EnvUnset); !ok {
656				return true
657			}
658		}
659		if si.EnvEquals != nil {
660			if val, ok := os.LookupEnv(si.EnvEquals.Var); ok && val == si.EnvEquals.Value {
661				return true
662			}
663		}
664		if si.FileMissing != "" {
665			path := si.FileMissing
666			if !strings.HasPrefix(path, "/") {
667				path = configDir + "/" + path
668			}
669			if _, err := os.Stat(path); os.IsNotExist(err) {
