		return rep
	}
	if _, err := url.Parse(reportURL); err != nil {
		fmt.Fprintf(os.Stderr, "warning: invalid report-url: %v\n", err)
		return rep
	}
	push := reporter.NewPushReporter(reportURL, reportAPIKey)
	return reporter.NewMultiReporter(rep, push)
}

